import { jsPDF } from 'jspdf';
import i18next from 'i18next';

/**
 * 证书生成服务 - 用于创建可下载的证书PDF
 */
class CertificateGenerator {
  /**
   * 根据证书数据生成PDF证书
   * @param {Object} certificate - 证书数据
   * @returns {Promise<Blob>} 返回PDF Blob
   */
  static generateCertificatePDF(certificate) {
    return new Promise((resolve, reject) => {
      try {
        // 获取当前语言
        const currentLanguage = i18next.language;
        const isEnglish = currentLanguage === 'en' || currentLanguage.startsWith('en-');

        // 创建PDF文档 (A4横向)
        const doc = new jsPDF({
          orientation: 'landscape',
          unit: 'mm',
          format: 'a4',
        });

        // 设置文档属性
        doc.setProperties({
          title: `${certificate.name} - ${isEnglish && certificate.english_course ? certificate.english_course : certificate.course} Certificate`,
          subject: 'Stratford International University Certificate',
          author: 'Stratford International University',
          keywords: 'certificate, education, diploma',
          creator: 'SIU Certificate System',
        });

        // 添加水印
        this.addWatermark(doc);

        // 加载证书SVG作为背景并处理后续操作
        this.loadSVGBackground(doc, certificate)
          .then(() => {
            // 添加证书详细信息
            this.addCertificateDetails(/* doc, certificate */);

            // 添加QR码 (用于验证)
            this.addVerificationQR(/* doc, certificate */);

            // 生成PDF并返回
            const pdfBlob = doc.output('blob');
            resolve(pdfBlob);
          })
          .catch(error => {
            console.error('加载SVG背景失败:', error);
            reject(error);
          });
      } catch (error) {
        console.error('PDF生成错误:', error);
        reject(error);
      }
    });
  }

  /**
   * 对外公开的下载证书方法
   * @param {Object} certificate - 证书数据
   * @returns {Promise<boolean>} 下载是否成功
   */
  static async downloadCertificate(certificate) {
    try {
      // 从内存中获取处理好的SVG
      let svgImage;
      if (certificate.processedImage && certificate.processedImage.startsWith('blob:')) {
        const response = await fetch(certificate.processedImage);
        svgImage = await response.text();
      } else {
        // 如果没有处理好的图像，获取原始SVG并处理
        const response = await fetch(certificate.image);
        let svgText = await response.text();
        
        // 替换占位符
        svgText = svgText.replace(/\[RECIPIENT NAME\]/g, certificate.name);
        svgText = svgText.replace(/\[DATE\]/g, certificate.date);
        svgText = svgText.replace(/\[CERTIFICATE-ID\]/g, certificate.certificateId);
        svgText = svgText.replace(/\[PROGRAM\/DEGREE\]/g, certificate.course);
        svgText = svgText.replace(/\[HASH\]/g, 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase());
        
        svgImage = svgText;
      }

      // 创建blob和URL用于下载
      const blob = new Blob([svgImage], { type: 'image/svg+xml' });
      const svgUrl = URL.createObjectURL(blob);

      // 为转换创建一个图像元素
      const img = new Image();
      
      // 创建PDF时增加证书高级样式，等待图像加载完成
      return new Promise((resolve, reject) => {
        img.onload = function() {
          try {
            // 创建一个新的PDF A4大小
            const pdf = new jsPDF({
              orientation: 'landscape',
              unit: 'mm',
              format: 'a4'
            });
            
            // 添加专业背景
            pdf.setFillColor(252, 252, 250);
            pdf.rect(0, 0, pdf.internal.pageSize.getWidth(), pdf.internal.pageSize.getHeight(), 'F');
            
            // 添加浅色水印背景
            pdf.setTextColor(240, 240, 245);
            pdf.setFontSize(60);
            pdf.setFont('helvetica', 'bold', 'normal');
            pdf.text('STRATFORD', pdf.internal.pageSize.getWidth() / 2, 70, { align: 'center', angle: 45, opacity: 0.1 });
            pdf.text('UNIVERSITY', pdf.internal.pageSize.getWidth() / 2, 100, { align: 'center', angle: 45, opacity: 0.1 });
            
            // 添加装饰性边框
            const pageWidth = pdf.internal.pageSize.getWidth();
            const pageHeight = pdf.internal.pageSize.getHeight();
            
            // 绘制金色边框
            pdf.setDrawColor(173, 151, 79); // 金色
            pdf.setLineWidth(1);
            pdf.rect(10, 10, pageWidth - 20, pageHeight - 20, 'S');
            
            // 绘制第二层边框
            pdf.setDrawColor(0, 48, 135); // 深蓝色
            pdf.setLineWidth(0.5);
            pdf.rect(15, 15, pageWidth - 30, pageHeight - 30, 'S');
            
            // 计算PDF内的图像尺寸和位置
            const imgWidth = pageWidth - 40;
            const imgHeight = (img.height * imgWidth) / img.width;
            const x = 20;
            const y = (pageHeight - imgHeight) / 2;
            
            // 将SVG添加到PDF
            pdf.addImage(img.src, 'SVG', x, y, imgWidth, imgHeight);
            
            // 添加专业印章 (圆形金色)
            const stampX = pageWidth - 60;
            const stampY = pageHeight - 40;
            
            // 绘制印章圆圈
            pdf.setDrawColor(173, 151, 79); // 金色
            pdf.setLineWidth(0.7);
            pdf.circle(stampX, stampY, 15, 'S');
            
            // 绘制内圈
            pdf.setDrawColor(173, 151, 79);
            pdf.setLineWidth(0.3);
            pdf.circle(stampX, stampY, 13, 'S');
            
            // 添加印章文字
            pdf.setTextColor(173, 151, 79);
            pdf.setFontSize(5);
            pdf.text('OFFICIAL', stampX, stampY - 5, { align: 'center' });
            pdf.text('UNIVERSITY', stampX, stampY, { align: 'center' });
            pdf.text('SEAL', stampX, stampY + 5, { align: 'center' });
            
            // 底部添加防伪提示
            pdf.setTextColor(100, 100, 100);
            pdf.setFontSize(6);
            pdf.text('This document contains multiple security features and can be verified at verify.stratford-university.edu', 
              pageWidth/2, pageHeight - 5, { align: 'center' });
            
            // 保存PDF
            pdf.save(`${certificate.name}-${certificate.certificateId}.pdf`);
            
            // 清理
            URL.revokeObjectURL(svgUrl);
            resolve(true);
          } catch (error) {
            console.error('Error generating PDF:', error);
            reject(error);
          }
        };
        
        img.onerror = function() {
          console.error('Failed to load image');
          reject(new Error('Failed to load certificate image'));
        };
        
        img.src = svgUrl;
      });
    } catch (error) {
      console.error('Error downloading certificate:', error);
      return false;
    }
  }

  /**
   * 添加水印
   * @param {jsPDF} doc - jsPDF文档实例
   */
  static addWatermark(doc) {
    // 设置水印颜色和透明度
    doc.setTextColor(200, 200, 200);
    doc.setGState(new doc.GState({ opacity: 0.2 }));

    // 添加水印文本
    doc.setFontSize(60);
    doc.text('Stratford International University', 150, 105, {
      align: 'center',
      angle: 45,
    });

    // 重置透明度
    doc.setGState(new doc.GState({ opacity: 1 }));
    doc.setTextColor(0, 0, 0);
  }

  /**
   * 加载SVG证书模板作为背景
   * @param {jsPDF} doc - jsPDF文档实例
   * @param {Object} certificate - 证书数据
   */
  static async loadSVGBackground(doc, certificate) {
    return new Promise((resolve, reject) => {
      try {
        // 获取当前语言
        const currentLanguage = i18next.language;
        const isEnglish = currentLanguage === 'en' || currentLanguage.startsWith('en-');

        // 创建图像对象
        const img = new Image();

        // 获取SVG内容并替换占位符
        fetch(certificate.processedImage || certificate.image)
          .then(response => response.text())
          .then(svgText => {
            // 替换SVG中的占位符
            svgText = svgText.replace(/\[RECIPIENT NAME\]/g, certificate.name);
            svgText = svgText.replace(/\[DATE\]/g, certificate.date);
            svgText = svgText.replace(/\[CERTIFICATE-ID\]/g, certificate.certificateId);

            // 根据当前语言选择课程名称和描述
            const courseTitle =
              isEnglish && certificate.english_course
                ? certificate.english_course
                : certificate.course;

            const courseDescription =
              isEnglish && certificate.english_description
                ? certificate.english_description
                : certificate.description;

            svgText = svgText.replace(/\[PROGRAM\/DEGREE\]/g, courseTitle);
            svgText = svgText.replace(/\[PROGRAM_DESCRIPTION\]/g, courseDescription);

            // 随机生成一个哈希作为区块链验证码
            const hash = 'SIU-' + Math.random().toString(36).substring(2, 10).toUpperCase();
            svgText = svgText.replace(/\[HASH\]/g, hash);

            // 创建SVG数据URL
            const svgBlob = new Blob([svgText], { type: 'image/svg+xml' });
            const url = URL.createObjectURL(svgBlob);

            // 设置图像源
            img.onload = function () {
              // 添加图像作为背景
              doc.addImage(img, 'SVG', 0, 0, 297, 210);

              // 释放URL对象
              URL.revokeObjectURL(url);

              resolve();
            };

            img.onerror = function (error) {
              URL.revokeObjectURL(url);
              reject(error);
            };

            img.src = url;
          })
          .catch(reject);
      } catch (error) {
        reject(error);
      }
    });
  }

  /**
   * 添加证书详细信息
   * @param {Object} certificate - 证书数据
   */
  static addCertificateDetails(/* doc, certificate */) {
    // 在合适的位置添加额外的证书信息
    // 注意：大部分信息已经包含在SVG模板中
  }

  /**
   * 添加验证QR码
   * @param {Object} certificate - 证书数据
   */
  static addVerificationQR(/* doc, certificate */) {
    // 为证书添加验证QR码
    // 这里可以实现实际的QR码生成逻辑
  }

  // 创建增强版证书SVG模板
  static generateEnhancedCertificateTemplate(certificateData) {
    // 这里是生成高质量SVG证书模板的基础代码
    const { name, course, date, certificateId } = certificateData;
    
    // 证书SVG模板
    return `
    <svg width="900" height="650" xmlns="http://www.w3.org/2000/svg">
      <!-- 背景层 -->
      <rect width="900" height="650" fill="#FFFEF9" />
      
      <!-- 装饰性边框 -->
      <rect x="20" y="20" width="860" height="610" stroke="#AA9651" stroke-width="3" fill="none" />
      <rect x="30" y="30" width="840" height="590" stroke="#003087" stroke-width="1.5" fill="none" />
      
      <!-- 水印背景图案 -->
      <g opacity="0.05">
        <path d="M450,150 L500,200 L450,250 L400,200 Z" fill="#003087" transform="rotate(45, 450, 200)" />
        <text x="450" y="325" font-family="Times New Roman" font-size="60" fill="#003087" text-anchor="middle" transform="rotate(-30, 450, 325)">STRATFORD</text>
        <text x="450" y="375" font-family="Times New Roman" font-size="60" fill="#003087" text-anchor="middle" transform="rotate(-30, 450, 375)">UNIVERSITY</text>
      </g>
      
      <!-- 证书顶部标题 -->
      <text x="450" y="100" font-family="Times New Roman" font-size="36" font-weight="bold" fill="#003087" text-anchor="middle">STRATFORD INTERNATIONAL UNIVERSITY</text>
      
      <!-- 校徽 -->
      <circle cx="450" cy="150" r="50" fill="#F5F5F5" stroke="#AA9651" stroke-width="2" />
      <circle cx="450" cy="150" r="45" fill="#003087" />
      <text x="450" y="140" font-family="Times New Roman" font-size="14" fill="white" text-anchor="middle">STRATFORD</text>
      <text x="450" y="160" font-family="Times New Roman" font-size="14" fill="white" text-anchor="middle">UNIVERSITY</text>
      <text x="450" y="175" font-family="Times New Roman" font-size="10" fill="white" text-anchor="middle">FOUNDED 2005</text>
      
      <!-- 证书正文内容 -->
      <text x="450" y="250" font-family="Times New Roman" font-size="24" fill="#000000" text-anchor="middle">This is to certify that</text>
      <text x="450" y="300" font-family="Times New Roman" font-size="36" font-weight="bold" fill="#000000" text-anchor="middle">${name}</text>
      <text x="450" y="350" font-family="Times New Roman" font-size="20" fill="#000000" text-anchor="middle">has successfully completed the requirements for the degree of</text>
      <text x="450" y="400" font-family="Times New Roman" font-size="28" font-weight="bold" fill="#003087" text-anchor="middle">${course}</text>
      
      <!-- 颁发日期和签名栏 -->
      <line x1="300" y1="500" x2="450" y2="500" stroke="#000000" stroke-width="1" />
      <line x1="550" y1="500" x2="700" y2="500" stroke="#000000" stroke-width="1" />
      <text x="375" y="525" font-family="Times New Roman" font-size="14" fill="#000000" text-anchor="middle">Dr. Elizabeth Stratford</text>
      <text x="375" y="545" font-family="Times New Roman" font-size="14" fill="#000000" text-anchor="middle">University President</text>
      <text x="625" y="525" font-family="Times New Roman" font-size="14" fill="#000000" text-anchor="middle">Prof. Robert Chen</text>
      <text x="625" y="545" font-family="Times New Roman" font-size="14" fill="#000000" text-anchor="middle">Dean, School of Business</text>
      
      <!-- 证书底部 -->
      <text x="450" y="580" font-family="Times New Roman" font-size="16" fill="#000000" text-anchor="middle">Issued on ${date}</text>
      <text x="450" y="605" font-family="Times New Roman" font-size="16" fill="#000000" text-anchor="middle">Certificate ID: ${certificateId}</text>
      <text x="450" y="630" font-family="Times New Roman" font-size="12" fill="#555555" text-anchor="middle">Blockchain Verification: SIU-7FE9TTGH</text>
    </svg>
    `;
  }
}

export default CertificateGenerator;
